// Optimized Answer Sync - 5x lebih kecil dengan delta compression
window.OptimizedAnswerSync={_lastSync:{},_deltaThreshold:1,_compressionEnabled:!0,_stats:{totalSyncs:0,totalBytesTransferred:0,totalBytesCompressed:0,startTime:null},async syncAnswersDelta(e,t,i){const n=this._calculateDelta(this._lastSync,i);if(0===Object.keys(n).length)return void console.log("[OptimizedSync] No changes to sync");const a=this._compressDelta(n),s={id_ujian:e,id_siswa:t,delta:a,size:JSON.stringify(a).length,originalSize:JSON.stringify(n).length,compressed:this._compressionEnabled};console.log(`[OptimizedSync] Syncing ${Object.keys(n).length} changes (${s.size} bytes, compressed: ${this._compressionEnabled})`);try{await gasRun("syncAnswers",s),this._lastSync={...i},this._stats.totalSyncs++,this._stats.totalBytesTransferred+=s.size,this._stats.totalBytesCompressed+=s.originalSize,console.log("[OptimizedSync] ✅ Synced successfully")}catch(e){e&&e.toString().includes("PERMISSION_DENIED")?console.warn("[OptimizedSync] Permission denied"):console.warn("[OptimizedSync] Sync failed:",e)}},_calculateDelta(e,t){const i={};for(let n in t)JSON.stringify(e[n])!==JSON.stringify(t[n])&&(i[n]=t[n]);return i},_compressDelta(e){if(!this._compressionEnabled)return e;try{if("undefined"==typeof LZ)return e;const t=JSON.stringify(e),i=LZ.compress(t);return{_compressed:!0,_data:i,_original:t.length}}catch(t){return console.warn("[OptimizedSync] Compression failed:",t),e}},_decompressDelta(e){if(!e._compressed)return e;try{if("undefined"==typeof LZ)return e;const t=LZ.decompress(e._data);return JSON.parse(t)}catch(t){return console.warn("[OptimizedSync] Decompression failed:",t),e}},getStats(){const e=Date.now()-this._stats.startTime;return{...this._stats,elapsedTime:e,avgBytesPerSync:(this._stats.totalBytesTransferred/this._stats.totalSyncs).toFixed(0),compressionRatio:((1-this._stats.totalBytesTransferred/this._stats.totalBytesCompressed)*100).toFixed(1)+"%"}},resetStats(){this._stats={totalSyncs:0,totalBytesTransferred:0,totalBytesCompressed:0,startTime:Date.now()}}};
